mapper.select:
SELECT COUNT(*)
FROM daily_question_log
WHERE member_id = #{memberId}
  AND record_date = #{recordDate}
  AND status = #{status}

mapper.update:
UPDATE daily_question_log
SET status = 'EXITED'
WHERE daily_question_log_id = #{dailyQuestionLogId}
  AND member_id = #{memberId}
  AND status = 'STARTED'

UPDATE daily_question_log
SET response_second = #{responseSecond},
    status = #{status}
WHERE daily_question_log_id = #{dailyQuestionLogId}
  AND member_id = #{memberId}
  AND status = 'STARTED'
